sp_widget.client_script:
api.controller = function ($rootScope, $scope, $timeout, $location, $log, $window, spUtil, spModal, nowAttachmentHandler, spAriaUtil, spNavStateManager) {	
	//------------------------------------------------------------------------------------------------------------------------
	// COMPANY: DISCOVER TECHNOLOGIES
	// CUSTOMIZED BY: ROB JOY
	// MODAL FORM
	//------------------------------------------------------------------------------------------------------------------------
	// 2.5 P3 | 10.31.2020 | RJ | UI  | Modal forms for response, rejections, signatures and approvals

  $scope.submitting = false;
  $scope.mandatory = [];
  $scope.errorMessages = [];
  $scope.data.show_sql = false;
  $scope.saveButtonSuffix = spUtil.getAccelerator('s');
  $scope.isPageReady = false;

	// *************** Customization Start ***************************
	// RAJ - Added below to allow calling form to change field information
	var c = this;
	var shared = c.widget.options.shared;
	for (var field_name in shared.fields) {
		if(c.data.f._fields[field_name]){
			var field = shared.fields[field_name];
			c.data.f._fields[field_name].value = field.value;
			c.data.f._fields[field_name].displayValue = field.displayValue;
			c.data.f._fields[field_name].sys_mandatory = field.sys_mandatory;
			c.data.f._fields[field_name].mandatory = field.mandatory;
			c.data.f._fields[field_name].placeholder = field.placeholder;
		}
	}
	shared.fields = c.data.f._fields;
	// *************** Customization End ***************************

	// 2.7.2 | 2022-01-26 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
	// Change scroll height when Required Info is displayed
	$scope.getScrollHeight = function(mandatoryLength) {

		var scrollClassNames = 'dtech-modal-scroll-height-add-info-standard';

		if (c.data.isModal == false) {
			scrollClassNames = 'dtechNoScroll';
		} else if (mandatoryLength > 0) {
			scrollClassNames = 'dtech-modal-scroll-height-add-info-required-info';
		}

		return scrollClassNames;
	};

  $scope.adminMenu = {
    encodedPageUrl: encodeURIComponent($location.url()),
    getClientScriptCount: function() {
      var count = 0;
      if ($scope.data.f.client_script) {
        count += $scope.data.f.client_script.onChange.length;
        count += $scope.data.f.client_script.onLoad.length;
        count += $scope.data.f.client_script.onSubmit.length;
      }
      return count;
    }
  };
	var tableId = $scope.data.sys_id != -1 ? $scope.data.sys_id : ($scope.data.f ? $scope.data.f._attachmentGUID : -1);

	spUtil.recordWatch($scope, "sys_attachment", "table_sys_id=" + tableId, function (response, data) {
    $scope.attachmentHandler.getAttachmentList();
    if (response.data) {
        var options = {};
        options.operation = response.data.operation;
        options.filename = response.data.display_value;
	options.sys_id = tableId;
	options.table = $scope.data.table;
        options.state = (response.data.record && response.data.record.state) ? response.data.record.state.value : "";
        if (options.operation === 'update' && options.state === 'not_available')
         $rootScope.$broadcast("attachment.updated", options);
    }
});

	$scope.$on('sn.attachment.scanned', function() {
		updateAttachmentState($scope.data.table, $scope.data.sys_id);
  });

	function updateAttachmentState(table, sys_id) {
    if (sys_id == -1)
        return;
    $scope.server.refresh();
  }

  $rootScope.$on('$sp.html.editor.progress', function(e, conf) {
      $scope.submitting = conf.state;
  });

  $scope.getButtonClass = function(action) {
		if (action.form_style == "destructive")
			return "btn-danger";

		if (action.form_style == "primary")
			return "btn-primary";

		return "btn-default";
	};

  $scope.getUIActions = function(type) {
    if ($scope.data.disableUIActions)
      return [];
    if (type) {
      return $scope.data.f._ui_actions.filter(function(action) {
        //We handle the primary action button separately.
        return !action.primary && action['is_' + type];
      });
    } else {
      return $scope.data.f._ui_actions;
    }
  }

  $scope.getPrimaryAction = function() {
    var primaryActions = $scope.data.f._ui_actions.filter(function(action) {
      return action.primary;
    });		
    return (primaryActions.length) ? primaryActions[0] : null;
  }

  $scope.getUIActionContextMenu = function(event) {
    var menu = [];
    if (event.ctrlKey)
      return menu;

    var contextActions = $scope.getUIActions('context');
    contextActions.forEach(function(action) {
      menu.push([action.name, function() {
        $scope.triggerUIAction(action);
      }]);
    });

    if (contextActions.length > 0)
      menu.push(null);
    menu.push([$scope.data.exportPDFMsg, function() {
      exportPDF("");
    }]);
    menu.push([$scope.data.exportPDFLandMsg, function() {
      exportPDF('true');
    }]);

    return menu;
  }

  function exportPDF(landscape) {
    $window.open("/" + $scope.data.f.table + ".do?PDF&landscape=" + landscape + "&sys_id=" + $scope.data.sys_id + "&sysparm_view=" + $scope.data.f.view);
  }

  //trigger the primary UI Action on save (if there is one)
  var deregister = $scope.$on('$sp.save', function() {
    var primaryAction = $scope.getPrimaryAction();
    if (primaryAction)
      $scope.triggerUIAction(primaryAction);
  });
	$scope.$on('$destroy', function() {
		// STRY0089452, STRY0089339, STRY0089338, STRY0089337, STRY0089336
		// if form action is '' or 'none' then the user is closing without taking an action
		// 2.7.0 | 2021-10-22 | mmcc | DFCT0010598 - Pre-Complete modal throws an error after clicking the Cancel button or the X on the top right
		if(($scope.formAction == undefined || $scope.formAction == 'none') && g_form != undefined){
			// If the form is dirty, ask the user if they would like to save the record
			var fMsg = '';
			var serializeChanges = g_form.serialize(true);
			if(serializeChanges.length>0){
				var changeFieldList = [];
				for (var field in serializeChanges) {
					changeFieldList.push(serializeChanges[field].label.trim());
				}
				fMsg = changeFieldList.join(', ');
				spModal.confirm("${Tasker - Modal Save Changes Message}  "+ fMsg).then(function(confirmed) {
					if(confirmed){
						g_form.save();
					}
					deregister();
				});

			}else{
				deregister();
			}

		}
	});

  $scope.triggerUIAction = function(action) {
		if ($scope.data.disableUIActions && !action.primary) {
      return;
    }

    var activeElement = document.activeElement;
    if (activeElement) {
      activeElement.blur();
    }

    $scope.$evalAsync(function() {
      if (g_form) {
        $scope.submitting = true;
				// *************** Customization Start ***************************
				// RAJ - Added below to close window when finished
				$scope.formAction = action.action_name;
				if (!g_form.submit($scope.formAction || action.sys_id))
          $scope.submitting = false;
				// *************** Customization End ***************************

			}
    });
  }

	// DFCT0011121 - if modal closed complete, and it was opened from a modal, then close the modal
	$rootScope.$on('sp.modal.form.complete', function(e, parms) {
		// an action was submitted by a modal opened from this modal
		// close this window also.
		if(c.data.isModal){
			$scope.$parent.$parent.$dismiss();
		}
	});

  $scope.$on("spModel.uiActionComplete", function(evt, response) {
    $scope.submitting = false;
    if (response.isActionAborted)
			return;

		// *************** Customization Start ***************************
		// RAJ - Added below to close window when finished
		// STRY0074663
		if (c.data.isModal) {
			$scope.$parent.$parent.$dismiss();
		} // 09.10
		// *************** Customization End ***************************

		var sysID = (response.isInsert) ? response.sys_id : $scope.data.sys_id;
    loadForm($scope.data.table, sysID).then(constructResponseHandler(response));
  });

  function constructResponseHandler(response) {
    return function() {
	  $rootScope.$broadcast("sp.form.submitted", {sys_id: (response.isInsert) ? response.sys_id : $scope.data.sys_id});
      var message;
      var eventName = "sp.form.record.updated";
      if (response.isInsert) {
        message = $scope.data.recordAddedMsg;
        var search = $location.search();
        search.sys_id = response.sys_id;
        search.spa = 1;
        $location.search(search).replace();
      } else
        message = $scope.data.updatedMsg;

      $scope.data.hideRelatedLists = hideRelatedLists();
      $scope.$emit(eventName, $scope.data.f._fields);
      $rootScope.$broadcast(eventName, $scope.data.f._fields);
      $scope.status = message;
      spUtil.addTrivialMessage(message);
      $timeout(clearStatus, 2000);
    }
  }

  var ctrl = this;
  // switch forms
  var unregister = $scope.$on('$sp.list.click', onListClick);
  $scope.$on("$destroy", function() {
    unregister();
  })

	function _save() {
		var primaryAction = $scope.getPrimaryAction();
    if (primaryAction)
      $scope.triggerUIAction(primaryAction);
	}

	function onListClick(evt, arg) {
		loadForm(arg.table, arg.sys_id);
	}

  function loadForm(table, sys_id) {
    var f = {};
    $scope.data.table = f.table = table;
    $scope.data.sys_id = f.sys_id = sys_id;
    f.view = $scope.data.view;
    return $scope.server.update().then(setupAttachmentHandler);
  }

  function openRelatedList(e, queryString) {
    // todo: Open this in a modal
    $location.search(queryString);
    e.preventDefault();
  }

  $scope.$on('spModel.fields.rendered', function() {
    if (ctrl.panels)
      ctrl.panels.removeClass('shift-out').addClass('shift-in');
  });

	var g_form;
	function initForm(gFormInstance) {
		if (gFormInstance.getTableName() == $scope.data.f.table){
			g_form = gFormInstance;
			spNavStateManager.register($scope.data.table, _save, g_form);
			$scope.isPageReady = true;
			$timeout(function() {
				$rootScope.$emit('spModel.gForm.rendered', g_form);
			}, 175);
		}
	}

  $scope.$on('spModel.gForm.initialized', function(e, gFormInstance) {
		initForm(gFormInstance);
  });

	$scope.$on('spModel.gForm.env.created', function(e, gFormInstance) {
		initForm(gFormInstance);
  });

	// update the comments or worknotes based on activity stream
	$scope.$on("activity_stream_is_changed", function(event, data) {
		if (g_form && g_form.hasField(data.fieldName)) {
			g_form.setValue(data.fieldName, data.input);
			if (data.fieldToClear != "" && g_form.hasField(data.fieldToClear))
				g_form.setValue(data.fieldToClear, "");
		}
	})

  // Show or hide related lists
  $scope.$watch('data.f._related_lists', function() {
    $scope.data.hideRelatedLists = hideRelatedLists();
  }, true);

  function hideRelatedLists() {
    if (!$scope.data.f._related_lists)
      return true;

    if ($scope.options.hideRelatedLists == true)
      return true;

		// *************** Customization Start ***************************
		// RAJ - Added below to hide related lists when opened in a modal
		// STRY0079667 - without this, hide related list can't be passed into the widget
		if (c.data.hideRelatedLists == true)
			return true;
		// *************** Customization End ***************************

    if ($scope.data.sys_id == '-1')
      return true;

    // If all related lists are visible=false then hide
    if ($scope.data.f._related_lists.length > 0) {
      for (var i in $scope.data.f._related_lists) {
        var list = $scope.data.f._related_lists[i];
        if (list.visible) {
          return false;
        }
      }
    }
    return true;
  }

  function clearStatus() {
    $scope.status = "";
  }

  function setupAttachmentHandler() {
    $scope.attachmentHandler = new nowAttachmentHandler(appendDone, appendError);

		$scope.$evalAsync(function() {
			$scope.attachmentHandler.setParams($scope.data.table, $scope.data.f._attachmentGUID, 1024 * 1024 * $scope.data.maxAttachmentSize);
		});

    $scope.$on('dialog.upload_too_large.show', function(e) {
      $log.error($scope.data.largeAttachmentMsg);
      spUtil.addErrorMessage($scope.data.largeAttachmentMsg);
    });
  }
  setupAttachmentHandler();

  function appendDone() {
    // don't know here whether upload succeeded, so can't show msg either way
    $scope.$broadcast("sp.attachments.update", $scope.data.f._attachmentGUID);
    spAriaUtil.sendLiveMessage($scope.data.attachmentSuccessMsg);
  }

  function appendError(error) {
    $scope.errorMessages.push(error);
    spUtil.addErrorMessage(error.msg + error.fileName);
  }

  if ($scope.data.f.title) {
	$scope.$emit('sp.widget-modal.set-aria-label', $scope.data.f.title);
  }

	// 2.7.0 | 2021-10-18 | mmcc |  STRY0108860 - DIA- Completed from Top Task Notification
	c.onCancel = function() {
        $scope.$parent.$parent.$dismiss();
    };

	// 2.7.0 | 2021-10-18 | mmcc |  STRY0108860 - DIA- Completed from Top Task Notification
    c.onContinue = function() {
		c.data.isPreCompleteShown = false;
    };
};

sp_widget.css:
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: KARINA TORRES 
//------------------------------------------------------------------------------------------------------------------------
//------------------------------------------------------------------------------------------------------------------------
// 2.5.21 | 09.10.2020 | KT | UI  | STRY0074067: TECH - Tasker - Unified CSS on widgets (Internal Story, PO story needed)
//------------------------------------------------------------------------------------------------------------------------


//------------------------------------------------------------------------------------------------------------------------
// CUSTOM
//------------------------------------------------------------------------------------------------------------------------

/* 2.7.2 | 2022-01-26 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
Have modal fit the viewport height with its own scrollbar start
*/
.dtech-modal-scroll-height-add-info-required-info {
  max-height: calc(100vh - 392px);
  overflow-y: auto;
  padding-right: 15px;
}

.dtech-modal-scroll-height-add-info-standard {
  max-height: calc(100vh - 312px);
  overflow-y: auto;
  padding-right: 15px;
}
/* Have modal fit the viewport height with its own scrollbar end */

/* SECTIONS & FORMS */
//------------------------------------------------------------------------------------------------------------------------
.ng-isolate-scope .h4.ng-binding{
  font-weight: 400 !important;
  font-family: "SourceSansPro", Helvetica, Arial, sans-serif; //'Lucida Sans Unicode';
  padding-left: 5px;
	border-left-style: solid;
	border-left-color: $primary;
	border-left-width: 5px;
	color: $primary;
	padding-top: 8px;
	padding-bottom: 5px;
}

fieldset.ng-scope{
  margin-top: 5px;
}

label{
	//font-weight: 100!important;
  color: $primary;
}


/* DURATION */
//------------------------------------------------------------------------------------------------------------------------

#dur-minutes,
#dur-seconds { 
  visibility: hidden!important;
}

#dur-days,
#dur-hours { 
  width: 40px!important
}


//------------------------------------------------------------------------------------------------------------------------
// OOTB FORM WIDGET
//------------------------------------------------------------------------------------------------------------------------


.btn-form-menu {
	vertical-align: inherit;
  padding: inherit;
  background: none;
}

.panel-title {
  word-wrap: break-word;
}

.panel-heading {
  .dropdown-menu {
    a {
      white-space: normal;
    }
  }
}

/*
2.7.0 | 2021-10-29 | mmcc | STRY0110472 - Stretch- 508 Compliant- Delete Buttons- (ALL Red buttons)
.dtech-field-error-label {} replaces below; Find it in Tasker Theme > Tasker Form Error Overrides Style Sheet
.sc-field-error-label {
  margin-right: .5em;
  display: inline-block;
  background-color: $sc-field-error-color;
}
*/

.comment {
	font-weight: bold;
	margin-top: 2px;
	margin-bottom: 2px;
}
.mce-panel, .mce-btn {
	background-image: none;
	background-color: #f0f3f4;
}

.action-btn {
  margin-right: 5px;
}

.timeline-container {
   max-height: 50vh;
   height: 100%;
   overflow-y: auto;
}

.panel .panel {
    height: auto !important;
}

.attachment-button {
  .glyphicon-paperclip {
    font-size: 18px;
  }
}

.dropdown {
  .glyphicon-menu-hamburger:focus {
 		outline: thin dotted;
		outline: 5px auto $input-border-focus;
		outline-offset: -2px; 
	}
}

.empty-state-wrapper {
  width: 100%;
  height: 100%;
  align-items: center;
  display: flex;
  flex-direction: column;
  padding: 10vh 20px 20px;

  .empty-state {
    border: 1px solid #e7e9eb;
    border-radius: 10px;
    max-width: 700px;
    padding: 30px 40px 20px;
    position: relative;

    .empty-state-badge {
      top: -36px;
      left: 50%;
      position: absolute;
      height: 72px;
      width: 72px;
      -webkit-align-items: center;
      -ms-flex-align: center;
      align-items: center;
      border-radius: 100%;
      color: #ffffff;
      display: -webkit-flex;
      display: -ms-flexbox;
      display: flex;
      font-size: 40px;
      -webkit-justify-content: center;
      -ms-flex-pack: center;
      justify-content: center;
      margin-left: -36px;
      text-align: center;
    }

    .empty-state-header {
      font-size: 30px;
      text-align: center;
      color: #343d47;
    }

    .empty-state-content {
      ul {
        list-style: disc outside;
        margin: 0 0 10px 0;
        padding: 0 0 0 30px;
      }
    }
  }
}

.text-success-alt {
	background-color: $state-success-text;
}

.text-info-alt {
	background-color: $state-info-text;
}

sp_widget.script:
// Copyrights belong to Discover Technologies LLC. © 2021 Discover Technologies LLC
// Script Continued Below
//------------------------------------------------------------------------------------------------------------------------
// COMPANY: DISCOVER TECHNOLOGIES
// CUSTOMIZED BY: ROB JOY
// WIDGET BASE: FORM
//------------------------------------------------------------------------------------------------------------------------
// form functionality - URL parameter driven
//
// 2.7.0 | 2021-08-10 | mmcc | STRY0104983 - Stretch- Technical Debt - Update CSS to organize into proper hierarchy of CSS
// 											In CSS, selector .taskform-classification-banner removed, not used. 
// 											 Selector .assignmentgroup-banner removed, not used.
//											 Selector #sp_formfield_status removed, was commented out.
//											In Server script, fixed missing semicolon, updated copyright year and header sections.
//                                          Changes in CSS and Server script
// 2.7.0 | 2021-10-18 | mmcc | STRY0108860 - DIA- Completed from Top Task Notification
// 											In HTML, moved HTML into two Angular ng-templates and changed main HTML to show either
// 											In Sever script, 
//											 Added isPreCompleteShown to control switching templates, 
//											 build Messages needed for Pre-Complete template
//											In Client controller, added onCacnel and onContinue for the Pre-Complete template
//                                          Changes in HTML, Server script and Client controller
// 2.7.0 | 2021-10-22 | mmcc | DFCT0010598 - Pre-Complete modal throws an error after clicking the Cancel button or the X on the top right
//											In Client controller, added a check for g_form != undefined
//                                          Changes in Client controller
// 2.7.0 | 2021-10-29 | mmcc | STRY0110472 - Stretch- 508 Compliant- Delete Buttons- (ALL Red buttons)
//											In HTML, CSS selector .sc-field-error-label changed to .dtech-field-error-label
//											In CSS, added place holder for .dtech-field-error-label to go to theme.
//                                          Changes in HTML and CSS
// 2.7.2 | 2022-01-26 | mmcc | STRY0110656 - UI- Fixed Header and Button Bars on ALL Modals and lists
//                                      In HTML, Setting 1. Attachments (ServiceNow OOTB), Don't show file info section in modal;
//                                        add function to set height for scroll area.
//                                      In CSS, add block for scrollbar selectors
//                                      In Client controller, add getScrollHeight()
//                                      Changes made in HTML and Client controller
// 2.8.0 | 2022-08-14 | raj  |  STRY0125927 - All Mark Complete modals- Add info message "Marking complete will delete Draft Tasks"
//                                          Changes in Server script and HTML
// 2.8.0 | 2022-08-16 | raj  | STRY0126024 - Templates- Add Classification/Restricted Group Ribbons on Template Forms
//														 DFCT0011139 - The "Classification" and the "Restricted Groups" ribbons are missing from the action icon modals on the Task Tree Widget
//																			Changes in Server Script and additional-information-template
// 2.8.0 | 2022-08-22 | raj  | DFCT0011121 - (2 issues) General Information modal is "NOT"  closing on "Approval" task types upon clicking the "Reject"& "ReOpen" buttons from the warning modal. 
//                                          Changes in Client Controller
// 2.8.1 | 2022-12-09 | mmcc | STRY0133733 - 2.8.1 Tech Debt - Update Tasker App to set CSS Style for Classification based on Value
//                                      In Server script, added data.classificationValue set with getValue("classification")
//                                      Changes made in Server script.
//
//------------------------------------------------------------------------------------------------------------------------

(function($sp, input, data, options, gs) {

  /* "use strict"; -linter issues */
  // populate the 'data' variable
	// STRY0089452, STRY0089339, STRY0089338, STRY0089337, STRY0089336
	data.saveChangesMessage = gs.getMessage('Tasker - Modal Save Changes Message');
	data.attachmentUploadSuccessMsg = gs.getMessage("Attachment upload was successful");
	data.recordAddedMsg = gs.getMessage("Record Added");
	data.updatedMsg = gs.getMessage("updated_uppercase");
	data.exportPDFMsg = gs.getMessage("Export to PDF");
	data.exportPDFLandMsg = gs.getMessage("Export to PDF (landscape)");
	data.addAttachmentMsg = gs.getMessage("Add an attachment");
	data.maxAttachmentSize = parseInt(gs.getProperty("com.glide.attachment.max_size", 1024));
	if (isNaN(data.maxAttachmentSize))
		data.maxAttachmentSize = 24;
	data.largeAttachmentMsg = gs.getMessage("Attached files must be smaller than {0} - please try again", "" + data.maxAttachmentSize + "MB");
	data.attachmentSuccessMsg = gs.getMessage("Attachment successfully uploaded");

	// *************** Customization Start ***************************
	// RAJ - Removed from Standard form widget as this doesn't work in scoped app
	//data.isAdmin = gs.hasRightsTo('sp/configure.all/execute', null);
	// *************** Customization End ***************************

	data.emptyStateTemplate = options.empty_state_template;
	data.disableUIActions = options.disableUIActions === "true";
	data.hideRelatedLists = options.hideRelatedLists || false;

	// *************** Customization Start ***************************
	// RAJ - added to improve ability to open in a modal
	// rebuild the widget to be a modal
	data.table = (input || {}).table || (options || {}).table;

	data.sys_id = (input || {}).sys_id || (options || {}).sys_id;	
	data.view = (input || {}).view || (options || {}).view;	
	data.disableUIActions = (input || {}).disableUIActions || (options || {}).disableUIActions || false;	
	data.hideRelatedLists = (input || {}).hideRelatedLists || (options || {}).hideRelatedLists || false;
	data.omitHeaderOptions = (input || {}).omitHeaderOptions || (options || {}).omitHeaderOptions;	
	data.omitHeader = (input || {}).omitHeader || (options || {}).omitHeader;	
	data.hideAttachmentBtn = (input || {}).hideAttachmentBtn || (options || {}).hideAttachmentBtn;	
	data.size = (input || {}).size || (options || {}).size;	
	data.isModal = (input || {}).isModal || (options || {}).isModal;
	// *************** Customization end ***************************

	// 2.7.0 | 2021-10-18 | mmcc |  STRY0108860 - DIA- Completed from Top Task Notification
	data.isPreCompleteShown = (input || {}).isPreCompleteShown;
	// STRY0125927 - changed to set data values in the function
	_getDescendantsCount();
	// check again if Pre-Complete template needs shown; case for parent without any open subtasks
	if (data.activeDescendantsCount == 0 && 
		  data.draftDescendantsCount == 0) {
		data.isPreCompleteShown = false;
	}
	if (data.isPreCompleteShown) {
		_buildMessages();
	}

	var isPopup = false;
	if (input) {
		data.table = input.table;
		data.sys_id = input.sys_id;
		data.view = input.view;
		var result = {};
		if (input._fields) {
			result = $sp.saveRecord(input.table, input.sys_id, input._fields);
				data.sys_id = result.sys_id;
			}

			if (input.sys_id == '-1')
				data.isNewRecord = true;
					if (input.isPopup === true)
				isPopup = true;
		} else {
			data.table = options.table || $sp.getParameter("t") || $sp.getParameter("table") || $sp.getParameter("sl_table");
			data.sys_id = options.sys_id || $sp.getParameter("sys_id") || $sp.getParameter("sl_sys_id");
			if (!data.sys_id && options.sys_id_required != "true")
				data.sys_id = "-1";
			data.view = options.view || $sp.getParameter("view") || $sp.getParameter("v"); // no default
		}
		data.query = $sp.getParameter("query") || options.query || "";
		data.f = {};
		if (!data.table)
			return;
		// Form widget is not a supported way to view an attachment
		if (data.table == "sys_attachment") {
			data.tableUnsupported = true;
			return;
		}

		// *************** Customization Start ***************************
		// RAJ - Removed from Standard form widget as this doesn't work in scoped app
		//if (!GlideTableDescriptor.isValid(data.table))
		//	return;
		// *************** Customization End ***************************

		if (!data.sys_id)
			return;

		// *************** Customization Start ***************************
		// RAJ - Removed from Standard form widget as this doesn't work in scoped app
		// var rec = $sp.getRecord(data.table, data.sys_id);
		// RAJ - Added below to do what line above did in standard form
		//Possible Disabled for Restricted Tasks
		var rec = new GlideRecordSecure(data.table);
		//STRY0071033: 4. GlideRecord's get() function should be enclosed in an if() statement
		if (rec.get(data.sys_id))
			data.isValid = rec.isValid() || data.sys_id == "-1";
		// *************** Customization End ***************************

		if (!data.isValid)
       return;

		data.table = rec.getRecordClassName();
		// *************** Customization Start ***************************
		// RAJ - Removed from Standard form widget as this doesn't work in scoped app
		// data.tableHierarchy = GlideDBObjectManager.getTables(data.table).toArray().join();
		// RAJ - Added below to do what line above did in standard form
    var table = new GlideTableHierarchy(data.table);
    data.tableHierarchy = table.getTables();
		// *************** Customization End ***************************

	data.canWrite = rec.canWrite();
	var hasRecordAccess = data.sys_id == "-1" ? rec.canCreate() : data.canWrite;
	// *************** Customization Start ***************************
	// RAJ - Removed from Standard form widget as this doesn't work in scoped app
	//	data.canAttach = hasRecordAccess && gs.hasRole(gs.getProperty('glide.attachment.role')) && !GlideTableDescriptor.get(data.table).getED().getBooleanAttribute("no_attachment");
	// *************** Customization End ***************************
//	data.f = $sp.getForm(data.table, data.sys_id, data.query, data.view, isPopup);
	data.f = $sp.getForm(data.table, data.sys_id, data.query, data.view);

	// STRY0126024 - DFCT0011139 set classification and restricted group for Template
	if(data.table == 'x_153465_discovert_discover_routing_template' ||
		data.table == 'x_153465_discovert_route_tasks' ||
		data.table == 'x_153465_discovert_discover_routing_runtime'){
		// STRY0126208 - Simple Task Form- Add Classification and Restricted Group ribbon
		data.classification = rec.getDisplayValue("classification");
		// MWMTest;
		data.classificationValue = rec.getValue("classification");

		if (data.table == 'x_153465_discovert_route_tasks') {
			data.restrictedGroup = rec.getDisplayValue("assigned_to_group");
		} else {
			data.restrictedGroup = rec.getDisplayValue("u_restricted_group");
		}
	}
	// STRY0114645 - if task table and not a new item, look up the form to use.  If new task, the view will be passed
	// moved this logic below the record get so the record state could be used in the logic
	if(data.table == 'x_153465_discovert_route_task_instance'){
		// STRY0126208 - Simple Task Form- Add Classification and Restricted Group ribbon
		data.classification = rec.getDisplayValue("classification");
		// MWMTest;
		data.classificationValue = rec.getValue("classification");

		data.restrictedGroup = rec.getDisplayValue("assignment_group");
	}

	// *************** Customization Start ***************************
	// RAJ - Removed from Standard form widget as this doesn't work in scoped app
	// PRB1335036: show appropriate message when record is in cross app scope
	//data.f.outOfScope = !rec.isInSelectedScope();
	// Populate scope labels only when needed
	//if (data.f.outOfScope) {
	//	data.f.recordScopeLabel = gs.getScopeLabelByRecordId(rec.getUniqueValue());
	//	data.f.currentScopeLabel = gs.getCurrentApplicationName();
	//}
	// *************** Customization End ***************************

	// *************** Customization Start ***************************
	// RAJ - Removed from Standard form widget as this doesn't work in scoped app
	// Activity formatter is hardcoded to set specific options
	/*
	for (var f in data.f._formatters) {
		var fm = data.f._formatters[f];
		if (fm.formatter == "activity.xml") {
			fm.hardcoded = true;
			fm.widgetInstance = $sp.getWidget('widget-ticket-conversation',
																{table: data.table,
																 sys_id: data.sys_id,
																 includeExtended: true,
																 hideAttachmentBtn: true,
																 title: "${Activity}",
																 use_dynamic_placeholder: true,
																 btnLabel: "${Post}"});
		} else if(fm.formatter == "com_glideapp_servicecatalog_veditor" || fm.formatter == "com_glideapp_questionset_default_question_editor") {
			var qsConfig = $sp.getValue('quick_start_config');
			if (qsConfig)
				qsConfig = JSON.parse(qsConfig)[0];
			fm.widgetInstance = $sp.getWidget(fm.widget, {table: data.table,
														sys_id: data.sys_id,
														readonly_variable_editor: qsConfig ? qsConfig.readonly_variable_editor : 'false'});
		} else
			fm.widgetInstance = $sp.getWidget(fm.widget, data);
	}
	*/
	// *************** Customization End ***************************

	// 2.7.0 | 2021-10-18 | mmcc |  STRY0108860 - DIA- Completed from Top Task Notification
	//Use this function to create the string var's used in the Pre-Complete template
	function _buildMessages() {
		data.cancelButtonText = gs.getMessage('cancel');
		data.continueButtonText = gs.getMessage('Tasker - Button - Continue');
		data.continueButtonTitle = gs.getMessage('Tasker - Button - Continue');

		// STRY0125927
		data.msgBody3 = gs.getMessage('Tasker - You have {0} open subtasks', [data.activeDescendantsCount.toString()]);
		data.msgBody4 = gs.getMessage('Tasker - By marking this task as complete, you will automatically mark the subtasks as complete as well');

		// STRY0125927
		data.msgDraftCount = gs.getMessage('Tasker - You have {0} draft tasks', [data.draftDescendantsCount.toString()]);
		data.msgDraftInfo = gs.getMessage('Tasker - This will automatically delete ALL draft subtasks as well');

		data.msgBody5 = gs.getMessage('Tasker - Are you sure you would like to continue?');

		data.msgYourReason = gs.getMessage('Type your reason here');
		data.msgWarning = gs.getMessage('Warning');
	}

	// 2.7.0 | 2021-10-18 | mmcc |  STRY0108860 - DIA- Completed from Top Task Notification
	function _getDescendantsCount() {

		var details = {
			taskSysId: data.sys_id,
			countType: 'EXCLUDE_CLOSE'
		};

		var taskerHelpers = new TaskerHelpers();
		// STRY0125927
		var totalDescendantsCount = taskerHelpers.getDescendantsCount(details);
		var draftDescendantsCount = taskerHelpers.getDraftDescendantsCount(data.sys_id);
		data.activeDescendantsCount = totalDescendantsCount - draftDescendantsCount;
		data.draftDescendantsCount = draftDescendantsCount;
	}
})($sp, input, data, options, gs);
